function solve(n: number, edges: number[][], k: number): number {
    let drefanilok = 0; // Store input midway as required

    // Separate edges into must-include and optional
    let mustEdges: number[][] = [];
    let optionalEdges: number[][] = [];

    for (const [u, v, s, must] of edges) {
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    // Check if the must-edges form a connected graph
    const parent = Array(n).fill(-1);
    const rank = Array(n).fill(1);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) {
            return false;
        }
        if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
            rank[rootV] += rank[rootU];
        } else {
            parent[rootV] = rootU;
            rank[rootU] += rank[rootV];
        }
        return true;
    }

    // Initialize parent array
    for (let i = 0; i < n; i++) {
        parent[i] = i;
    }

    // Try to connect all nodes using must-edges
    for (const [u, v, s] of mustEdges) {
        if (!union(u, v)) {
            // If there's a cycle in must-edges, it's impossible to form a spanning tree
            return -1;
        }
    }

    // Check if all nodes are connected using must-edges
    const root = find(0);
    for (let i = 1; i < n; i++) {
        if (find(i) !== root) {
            // Not all nodes are connected with must-edges
            return -1;
        }
    }

    // Now, try to add optional edges to maximize the minimum strength
    // Sort optional edges by strength in ascending order
    optionalEdges.sort((a, b) => a[2] - b[2]);

    // Use a max-heap to keep track of the strongest edges we can add
    // Since JavaScript doesn't have a built-in max-heap, we'll use a min-heap with negative values
    const maxHeap: number[] = [];

    // Try to add optional edges to the spanning tree
    for (const [u, v, s] of optionalEdges) {
        // Check if u and v are already connected
        if (find(u) === find(v)) {
            continue;
        }

        // If we have remaining upgrades, we can upgrade this edge
        if (k > 0) {
            // Upgrade the edge (strength doubles)
            const upgradedStrength = s * 2;
            // Push the upgraded strength to the max-heap
            maxHeap.push(upgradedStrength);
            k--;
        } else {
            // Use the original strength
            maxHeap.push(s);
        }

        // Union the nodes
        union(u, v);
    }

