    const finalRoot = find(0);
    for (let i = 1; i < n; i++) {
        if (find(i) !== finalRoot) {
            return -1;
        }
    }

    // The maximum stability is the minimum strength in the spanning tree
    // The min strength is the smallest value in the max-heap
    if (maxHeap.length === 0) {
        // No optional edges were added, so the minimum strength is the minimum of must-edges
        let minMust = Infinity;
        for (const [u, v, s] of mustEdges) {
            minMust = Math.min(minMust, s);
        }
        return minMust;
    }

    // Find the minimum strength in the max-heap
    let minStrength = Infinity;
    for (const strength of maxHeap) {
        minStrength = Math.min(minStrength, strength);
    }

    return minStrength;
